<select class="form-control" onchange="MissionsModule.setF('siteId',this.value)"><option value="">Tous sites</option>${sites.map(s=>`<option value="${s.id}" ${this.f.siteId===s.id?'selected':''}>${s.name}</option>`).join('')}</select>
