<td><div class="table-actions"><button class="btn btn-sm btn-ghost" onclick="MissionsModule.openDetail('${m.id}')">📄</button><button class="btn btn-sm btn-ghost" onclick="MissionsModule.openForm('${m.id}')">✏️</button><button class="btn btn-sm btn-ghost" onclick="MissionsModule.del('${m.id}')">🗑️</button></div></td>
