save(existId){const siteId=document.getElementById('mf-site')?.value,empId=document.getElementById('mf-emp')?.value,date=document.getElementById('mf-date')?.value,st=document.getElementById('mf-start')?.value,en=document.getElementById('mf-end')?.value;if(!siteId||!empId||!date||!st||!en){Toast.error('Remplissez tous les champs obligatoires');return}const ov=BL.checkOverlap(empId,date,st,en,existId||null);if(ov.length){const s=Storage.find('sites',ov[0].siteId);Toast.error(`Conflit: chevauchement avec "${s?.name||'?'}" (${ov[0].startTime}–${ov[0].endTime})`);return}const type=document.getElementById('mf-type')?.value||'menage_courant';if(!BL.haSkill(empId,type))Toast.warning("Agent sans la compétence requise (créé quand même)");const dur=Utils.timeToMin(en)-Utils.timeToMin(st),ex=existId?Storage.find('missions',existId):null;Storage.save('missions',{id:existId||Utils.uid(),siteId,employeeId:empId,date,startTime:st,endTime:en,type,estimatedDuration:dur,actualDuration:existId?(parseInt(document.getElementById('mf-actual')?.value)||ex?.actualDuration||null):null,status:document.getElementById('mf-status')?.value||'planifiee',qualityScore:existId?(parseFloat(document.getElementById('mf-quality')?.value)||null):null,qualityNotes:existId?(document.getElementById('mf-qnotes')?.value||''):'',checklist:ex?.checklist||[],consumablesUsed:ex?.consumablesUsed||[],notes:document.getElementById('mf-notes')?.value||'',createdAt:ex?.createdAt||Utils.now()});UI.closeModal();Toast.success(existId?'Mission modifiée':'Mission créée');App.refresh()},
