toggleCheck(mId,idx,el){const m=Storage.find('missions',mId);if(!m)return;if(!m.checklist?.length){m.checklist=((Config.get('checklistTemplates')||{})[m.type]||[]).map(t=>({task:t,done:false}))}m.checklist[idx].done=!m.checklist[idx].done;Storage.save('missions',m);el.classList.toggle('checked');el.querySelector('.checklist-checkbox').innerHTML=el.classList.contains('checked')?'✓':''},
